noncompliant:
// Union names not following convention (should start with uppercase)
union my_union {
    int one;
    int two;
};

// Type alias not following convention
using my_other_union = union {
    int one;
    int two;
};

// Snake_case naming
union data_container {
    int intValue;
    float floatValue;
};

compliant:
// Proper PascalCase naming
union MyUnion {
    int one;
    int two;
};

// Type alias with proper naming
using MyOtherUnion = union {
    int one;
    int two;
};

// Consistent naming convention
union DataContainer {
    int intValue;
    float floatValue;
};

// Anonymous union (exception)
union {
    int a;
    bool b;
} u; // OK by exception
